        AWQ_["AWQ\\nActivation-aware\\nSalient weight scaling\\n1.5-2x faster than GPTQ"]
        GGUF_["GGUF\\nMixed precision\\nCPU + Metal optimized\\nllama.cpp ecosystem"]
    end

